VALUES
  ('police-8b7f1efc-moex-00137', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '1970年代美國Missouri州Kansas警察巡邏實驗所呈現的結果，下列敘述何者正確？', '["整體而言，民眾的犯罪被害恐懼感會受不同巡邏區的影響而有不同", "商業人士對於犯罪及警察服務的感受，會因巡邏區組別不同而異", "不同巡邏形式，會影響民眾對於警察的滿意度", "不同巡邏形式並無顯著影響交通事故及傷亡情形"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00138', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Dunn（2012）在其著作「公共政策分析」一書中，提出以問題為中心的政策分析（problem-centered policy），常應用於警察工作上，其提出的5種政策分析方法（policy-analyticmethods），下列何 者錯誤？', '["問題建構（problemstructuring）", "預測（forecasting）", "描述（prescription）", "解釋（interpretation）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00139', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '近期政府推動「五力齊發」打詐犯罪預防策略，包含：識詐、堵詐、防詐、阻詐、懲詐共五大面 向，各面向主責機關及應用策略的搭配，下列何者錯誤？', '["「識詐力」由內政部推動「百斬車手獎五萬」專案", "「防詐力」由國家通訊傳播委員會主責，運用AI技術對抗深偽詐騙，建置「網路詐騙通報查 詢網」", "「阻詐力」由金融監督管理委員會督導金融機構控管人頭帳戶、強化虛擬資產防洗錢與信用卡 詐騙防制，並加速建置電子化通報機制", "「懲詐力」由法務部統籌檢警調持續追查詐騙集團，查扣不法所得並返還被害人款項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00140', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '荷蘭政府自 1984 年體驗到犯罪預防的重要，於 1985 年提出名為「社會與犯罪」（Society and Crime）的犯罪預防計畫。關於該計畫內容的說明，下列何者錯誤？', '["透過物理環境與結構工程的良好設計，減少犯罪行為發生的機會", "在公共場所以及犯罪發生率較高的地區設置監視設備", "強調社會治安問題須皆由司法部門或警察部門來執行", "強化青少年對大眾及社會的依附"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00141', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '關於刑事司法體系與社區犯罪預防模式兩者之比較，下列敘述何者正確？', '["就犯罪問題（對象）而言，刑事司法體系模式處理失序、恐懼、嚴重犯罪；社區犯罪預防模式 處理指標犯罪", "就組織設計而言，刑事司法體系模式為分權機構；社區犯罪預防模式為中央化組織", "就犯罪控制的優先順序（功能）而言，刑事司法體系模式在預防和控制犯罪；社區犯罪預防模 式在逮捕和處理違法者", "就警民關係而言，刑事司法體系模式中的警察保持中立和疏離；社區犯罪預防模式的警察代表 社區行動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00142', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'essay', '英文作文：（25分）
近年來，詐騙（scam）集團日益猖獗，針對此現象，請寫一篇長約 200
字的英文短文，首先在第一段中，說明詐騙常見的型態，其次在第二
段中，教導民眾如何預防詐騙。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00143', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '立法委員於審議經濟部之年度預算時，提議將某預算科目的一定比例移至其他科目，但預算 總額並未增加。依憲法及司法院大法官解釋，下列敘述何者正確？', '["立法委員本來即有審議預算的權力，故其提議並未牴觸憲法", "立法委員之預算變動有實質正當理由，其變動即屬合憲", "預算總額於移動後並無增加，即無增加政府支出，故非憲法所不許", "預算總額雖未增加，但就被移動而增加或追加之原預算項目而言，亦屬增加支出之提議， 而與憲法不符"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00144', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '依司法院大法官解釋，有關人民義務之規定，下列敘述何者正確？', '["行政機關得依憲法規定逕命人民履行該義務", "除憲法明定者外，國家不得課予人民其他義務", "就人民義務之具體內容，立法者有形成自由", "人民義務不適用憲法第23條之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00145', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '依司法院大法官解釋，有關總統之國家機密特權，下列敘述何者錯誤？', '["總統就國家機密事項於刑事訴訟程序，應享有拒絕證言權", "總統有拒絕提交相關證物之權", "就涉及總統國家機密特權範圍內之國家機密事項之訊問，是否妨害國家之利益，應由總統 證明之", "檢察官若以總統所提交相關證物作為終結偵查之處分，有造成國家安全危險之合理顧慮 者，應認有妨害國家利益之虞"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00146', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '下列何者享有憲法上之主權？', '["花蓮縣", "臺北市", "臺北市政府", "中華民國"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
